checks.run:
mkdir -p "$SANDBOX/test"
cat > "$SANDBOX/test/_grader.test.ts" <<'GRADER'
import { test } from "node:test";
import assert from "node:assert/strict";
import { mergeIntervals } from "../src/intervals.ts";

test("empty input", () => {
  assert.deepEqual(mergeIntervals([]), []);
});

test("single interval", () => {
  assert.deepEqual(mergeIntervals([[1, 3]]), [[1, 3]]);
});

test("classic overlap, already sorted", () => {
  assert.deepEqual(
    mergeIntervals([[1, 3], [2, 6], [8, 10], [15, 18]]),
    [[1, 6], [8, 10], [15, 18]],
  );
});

test("unsorted input is sorted before merging", () => {
  assert.deepEqual(mergeIntervals([[8, 10], [1, 3], [2, 6]]), [[1, 6], [8, 10]]);
});

test("touching intervals merge", () => {
  assert.deepEqual(mergeIntervals([[1, 2], [2, 3]]), [[1, 3]]);
});

test("fully contained intervals are absorbed", () => {
  assert.deepEqual(mergeIntervals([[1, 10], [2, 3], [4, 5]]), [[1, 10]]);
});

test("chained touching intervals collapse to one", () => {
  assert.deepEqual(mergeIntervals([[1, 4], [4, 5], [5, 6]]), [[1, 6]]);
});

test("disjoint intervals stay separate", () => {
  assert.deepEqual(mergeIntervals([[1, 2], [4, 5]]), [[1, 2], [4, 5]]);
});

test("does not mutate the input", () => {
  const input = [[3, 4], [1, 2]];
  const snapshot = JSON.parse(JSON.stringify(input));
  mergeIntervals(input);
  assert.deepEqual(input, snapshot);
});
GRADER
cd "$SANDBOX" && node --experimental-strip-types --test "test/_grader.test.ts"
